var surah015 = {
  number: 15,
  nameArabic: "al-Hijr",
  nameEnglish: "Al-Hijr",
  meaning: "The Rocky Tract",
  totalAyahs: 99,
  ayahs: [
    { number: 1, arabic: "الٓر ۚ تِلْكَ ءَايَٰتُ ٱلْكِتَٰبِ وَقُرْءَانٍۢ مُّبِينٍۢ", transliteration: "Aliflamra tilka ayatu alkitabi waquranin mubeenin", transliterationB: "Alif-Laaam-Raa; tilka Aayaatul Kitaabi wa Qur-aa-nim Mubeen", english: "L. R. These are the Ayats of Revelation,- of a Qur'an that makes things clear", romanUrdu: "Alif Laam Raa .. yeh aayat hain kitab e ilahi aur Quran e mubeen ki" },
    { number: 2, arabic: "رُّبَمَا يَوَدُّ ٱلَّذِينَ كَفَرُوا۟ لَوْ كَانُوا۟ مُسْلِمِينَ", transliteration: "Rubama yawaddu allatheena kafaroo law kanoo muslimeena", transliterationB: "Rubamaa yawaddul lazeena kafaroo law kaanoo muslimeen", english: "Again and again will those who disbelieve, wish that they had bowed (to Allah's will) in Islam", romanUrdu: "Baeed nahin ke ek waqt woh aa jaye jab wahi log jinhon ne aaj ( dawah e Islam ko qabool karne se) inkar kardiya hai pachta pachta kar kahenge ke kaash humne sar e tasleem kham kardiya hota" },
    { number: 3, arabic: "ذَرْهُمْ يَأْكُلُوا۟ وَيَتَمَتَّعُوا۟ وَيُلْهِهِمُ ٱلْأَمَلُ ۖ فَسَوْفَ يَعْلَمُونَ", transliteration: "Tharhum yakuloo wayatamattaAAoo wayulhihimu alamalu fasawfa yaAAlamoona", transliterationB: "Zarhum yaakuloo wa tatamatta'oo wa yulhihimul amalu fasawfa ya'lamoon", english: "Leave them alone, to enjoy (the good things of this life) and to please themselves: let (false) hope amuse them: soon will knowledge (undeceive them)", romanUrdu: "Chodo inhein khayein (eat) , peeyain (drink) mazey karein aur behlawe mein daale rahey inko jhooti umeed. Anqareeb inehin maloom ho jayega" },
    { number: 4, arabic: "وَمَآ أَهْلَكْنَا مِن قَرْيَةٍ إِلَّا وَلَهَا كِتَابٌۭ مَّعْلُومٌۭ", transliteration: "Wama ahlakna min qaryatin illa walaha kitabun maAAloomun", transliterationB: "Wa maaa ahlaknaa min qaryatin illaa wa lahaa kitaabum ma'loom", english: "Never did We destroy a population that had not a term decreed and assigned beforehand", romanUrdu: "Humne issey pehle jis basti ko bhi halaak kiya hai uske liye ek khaas mohlat e amal likhi jaa chuki thi" },
    { number: 5, arabic: "مَّا تَسْبِقُ مِنْ أُمَّةٍ أَجَلَهَا وَمَا يَسْتَـْٔخِرُونَ", transliteration: "Ma tasbiqu min ommatin ajalaha wama yastakhiroona", transliterationB: "Maa tasbiqu min ummatin ajalahaa wa maa yastaakhiroon", english: "Neither can a people anticipate its term, nor delay it", romanUrdu: "Koi qaum na apne waqt e muqarrar se pehle halaak ho sakti hai, na uske baad chooth sakti hai" },
    { number: 6, arabic: "وَقَالُوا۟ يَٰٓأَيُّهَا ٱلَّذِى نُزِّلَ عَلَيْهِ ٱلذِّكْرُ إِنَّكَ لَمَجْنُونٌۭ", transliteration: "Waqaloo ya ayyuha allathee nuzzila AAalayhi alththikru innaka lamajnoonun", transliterationB: "Wa qaaloo yaaa aiyuhal lazee nuzzila 'alaihiz Zikru innaka lamajnoon", english: "They say: \"O thou to whom the Message is being revealed! truly thou art mad (or possessed)", romanUrdu: "Yeh log kehte hain “Aey woh shaks jis par zikr nazil hua hai, tu yaqeenan deewana hai" },
    { number: 7, arabic: "لَّوْ مَا تَأْتِينَا بِٱلْمَلَٰٓئِكَةِ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ", transliteration: "Law ma tateena bialmalaikati in kunta mina alssadiqeena", transliterationB: "Law maa taateenaa bil malaaa'ikati in kunta minas saadiqeen", english: "Why bringest thou not angels to us if it be that thou hast the Truth", romanUrdu: "Agar tu saccha hai to hamare samne Farishton ko le kyun nahin aata?”" },
    { number: 8, arabic: "مَا نُنَزِّلُ ٱلْمَلَٰٓئِكَةَ إِلَّا بِٱلْحَقِّ وَمَا كَانُوٓا۟ إِذًۭا مُّنظَرِينَ", transliteration: "Ma nunazzilu almalaikata illa bialhaqqi wama kanoo ithan munthareena", transliterationB: "Maa nunazzilul malaaa'i kata illaa bilhaqqi wa maa kaanooo izam munzareen", english: "We send not the angels down except for just cause: if they came (to the ungodly), behold! no respite would they have", romanUrdu: "Hum Farishton ko yunhi nahin utaar diya karte, woh jab utarte hain to haqq ke saath utarte hain, aur phir logon ko mohlat nahin di jati" },
    { number: 9, arabic: "إِنَّا نَحْنُ نَزَّلْنَا ٱلذِّكْرَ وَإِنَّا لَهُۥ لَحَٰفِظُونَ", transliteration: "Inna nahnu nazzalna alththikra wainna lahu lahafithoona", transliterationB: "Innaa Nahnu nazalnaz Zikra wa Innaa lahoo lahaa fizoon", english: "We have, without doubt, sent down the Message; and We will assuredly guard it (from corruption)", romanUrdu: "Raha yeh zikr, to isko humne nazil kiya hai aur hum khud iske nigehbaan hain" },
    { number: 10, arabic: "وَلَقَدْ أَرْسَلْنَا مِن قَبْلِكَ فِى شِيَعِ ٱلْأَوَّلِينَ", transliteration: "Walaqad arsalna min qablika fee shiyaAAi alawwaleena", transliterationB: "Wa laqad arsalnaa min qablika fee shiya'il awwaleen", english: "We did send messengers before thee amongst the religious sects of old", romanUrdu: "(Aey Muhammad), hum tumse pehle bahut si guzri hui qaumon mein Rasool bhej chuke hain" },
    { number: 11, arabic: "وَمَا يَأْتِيهِم مِّن رَّسُولٍ إِلَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ", transliteration: "Wama yateehim min rasoolin illa kanoo bihi yastahzioona", transliterationB: "Wa maa yaateehim mir Rasoolin illaa kaanoo bihee yastahzi'oon", english: "But never came a messenger to them but they mocked him", romanUrdu: "Kabhi aisa nahin hua ke unke paas koi Rasool aaya ho aur unhone uska mazaak na udaya ho" },
    { number: 12, arabic: "كَذَٰلِكَ نَسْلُكُهُۥ فِى قُلُوبِ ٱلْمُجْرِمِينَ", transliteration: "Kathalika naslukuhu fee quloobi almujrimeena", transliterationB: "kazaalika naslukuhoo fee quloobil mujrimeen", english: "Even so do we let it creep into the hearts of the sinners", romanUrdu: "Mujrimeen ke dilon mein to hum is zikr ko isi tarah [salaakh ke manind(like a rod)] guzarte hain" },
    { number: 13, arabic: "لَا يُؤْمِنُونَ بِهِۦ ۖ وَقَدْ خَلَتْ سُنَّةُ ٱلْأَوَّلِينَ", transliteration: "La yuminoona bihi waqad khalat sunnatu alawwaleena", transliterationB: "Laa yu'minoona bihee wa qad khalat sunnatul awwaleen", english: "That they should not believe in the (Message); but the ways of the ancients have passed away", romanUrdu: "Woh ispar iman nahin laya karte. Qadeem (ancient times) se is qumash ke logon ka yahi tareeqa chala aa raha hai" },
    { number: 14, arabic: "وَلَوْ فَتَحْنَا عَلَيْهِم بَابًۭا مِّنَ ٱلسَّمَآءِ فَظَلُّوا۟ فِيهِ يَعْرُجُونَ", transliteration: "Walaw fatahna AAalayhim baban mina alssamai fathalloo feehi yaAArujoona", transliterationB: "Wa law fatahnaa 'alaihim baabam minas samaaa'i fazaloo feehi ya'rujoon", english: "Even if We opened out to them a gate from heaven, and they were to continue (all day) ascending therein", romanUrdu: "Agar hum unpar aasman ka koi darwaza khol detay aur woh din dahade usmein chadhne bhi lagte" },
    { number: 15, arabic: "لَقَالُوٓا۟ إِنَّمَا سُكِّرَتْ أَبْصَٰرُنَا بَلْ نَحْنُ قَوْمٌۭ مَّسْحُورُونَ", transliteration: "Laqaloo innama sukkirat absaruna bal nahnu qawmun mashooroona", transliterationB: "Laqaaloo innamaa sukkirat absaarunaa bal nahnu qawmum mashooroon", english: "They would only say: \"Our eyes have been intoxicated: Nay, we have been bewitched by sorcery", romanUrdu: "tab bhi woh yahi kehte ke hamari aankhon ko dhoka ho raha hai, balke humpar jaadu kardiya gaya hai" },
    { number: 16, arabic: "وَلَقَدْ جَعَلْنَا فِى ٱلسَّمَآءِ بُرُوجًۭا وَزَيَّنَّٰهَا لِلنَّٰظِرِينَ", transliteration: "Walaqad jaAAalna fee alssamai buroojan wazayyannaha lilnnathireena", transliterationB: "Wa laqad ja'alnaa fissamaaa'i buroojanw wa zaiyannaahaa linnaazireen", english: "It is We Who have set out the zodiacal signs in the heavens, and made them fair-seeming to (all) beholders", romanUrdu: "Yeh hamari kaar-farmayi hai ke aasman mein humne bahut se mazboot qiley (fortified spheres) banaye, unko dekhne walon ke liye muzayyan (adorn) kiya" },
    { number: 17, arabic: "وَحَفِظْنَٰهَا مِن كُلِّ شَيْطَٰنٍۢ رَّجِيمٍ", transliteration: "Wahafithnaha min kulli shaytanin rajeemin", transliterationB: "Wa hafiznaahaa min kulli Shaitaanir rajeem", english: "And (moreover) We have guarded them from every cursed devil", romanUrdu: "Aur har shaytaan e mardood se unko mehfooz kardiya" },
    { number: 18, arabic: "إِلَّا مَنِ ٱسْتَرَقَ ٱلسَّمْعَ فَأَتْبَعَهُۥ شِهَابٌۭ مُّبِينٌۭ", transliteration: "Illa mani istaraqa alssamAAa faatbaAAahu shihabun mubeenun", transliterationB: "Illaa manis taraqas sam'a fa atba'ahoo shihaabum mubeen", english: "But any that gains a hearing by stealth, is pursued by a flaming fire, bright (to see)", romanUrdu: "Koi shaytaan in mein raah nahin paa sakta, illa yeh ke kuch sun-gun le le, aur jab woh sun-gun lene ki koshish karta hai to ek shola roshan uska peecha karta hai" },
    { number: 19, arabic: "وَٱلْأَرْضَ مَدَدْنَٰهَا وَأَلْقَيْنَا فِيهَا رَوَٰسِىَ وَأَنۢبَتْنَا فِيهَا مِن كُلِّ شَىْءٍۢ مَّوْزُونٍۢ", transliteration: "Waalarda madadnaha waalqayna feeha rawasiya waanbatna feeha min kulli shayin mawzoonin", transliterationB: "Wal arda madadnaahaa wa alqainaa feehaa rawaasiya wa ambatnaa feehaa min kulli shai'im mawzoon", english: "And the earth We have spread out (like a carpet); set thereon mountains firm and immovable; and produced therein all kinds of things in due balance", romanUrdu: "Humne zameen ko phaylaya, us mein pahadh jamaye, usmein har naw ki nabataat theek theek napi tuli miqdar(measure) ke saath ugayi" },
    { number: 20, arabic: "وَجَعَلْنَا لَكُمْ فِيهَا مَعَٰيِشَ وَمَن لَّسْتُمْ لَهُۥ بِرَٰزِقِينَ", transliteration: "WajaAAalna lakum feeha maAAayisha waman lastum lahu biraziqeena", transliterationB: "Wa ja'alnaa lakum feehaa ma'aayisha wa mal lastum lahoo biraaziqeen", english: "And We have provided therein means of subsistence,- for you and for those for whose sustenance ye are not responsible", romanUrdu: "Aur is mein maishat ke asbaab faraham kiye, tumhare liye bhi aur un bahut si makhlooqat ke liye bhi jinke raziq tum nahin ho" },
    { number: 21, arabic: "وَإِن مِّن شَىْءٍ إِلَّا عِندَنَا خَزَآئِنُهُۥ وَمَا نُنَزِّلُهُۥٓ إِلَّا بِقَدَرٍۢ مَّعْلُومٍۢ", transliteration: "Wain min shayin illa AAindana khazainuhu wama nunazziluhu illa biqadarin maAAloomin", transliterationB: "Wa im min shai'in illaa 'indanaa khazaaa 'inuhoo wa maa nunazziluhooo illaa biqadarim ma'loom", english: "And there is not a thing but its (sources and) treasures (inexhaustible) are with Us; but We only send down thereof in due and ascertainable measures", romanUrdu: "Koi cheez aisi nahin jiske khazane hamare paas na hon, aur jis cheez ko bhi hum nazil karte hain ek muqarrar miqdar(measure) mein nazil karte hain" },
    { number: 22, arabic: "وَأَرْسَلْنَا ٱلرِّيَٰحَ لَوَٰقِحَ فَأَنزَلْنَا مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَسْقَيْنَٰكُمُوهُ وَمَآ أَنتُمْ لَهُۥ بِخَٰزِنِينَ", transliteration: "Waarsalna alrriyaha lawaqiha faanzalna mina alssamai maan faasqaynakumoohu wama antum lahu bikhazineena", transliterationB: "Wa arsalnar riyaaha la waaqiha fa anzalnaa minas samaaa'i maaa'an fa asqai naakumoohu wa maaa antum lahoo bikhaazineen", english: "And We send the fecundating winds, then cause the rain to descend from the sky, therewith providing you with water (in abundance), though ye are not the guardians of its stores", romanUrdu: "Baar-awar hawaon (fertilizing winds) ko hum hi bhejte hain, phir aasman se pani barsate hain, aur us pani se tumhein sairaab karte hain, is daulat ke khazana-daar tum nahin ho" },
    { number: 23, arabic: "وَإِنَّا لَنَحْنُ نُحْىِۦ وَنُمِيتُ وَنَحْنُ ٱلْوَٰرِثُونَ", transliteration: "Wainna lanahnu nuhyee wanumeetu wanahnu alwarithoona", transliterationB: "Wa innnaa la nahnu nuhyee wa numeetu wa nahnul waarisoon", english: "And verily, it is We Who give life, and Who give death: it is We Who remain inheritors (after all else passes away)", romanUrdu: "Zindagi aur maut hum dete hain, aur hum hi sab ke waris honay waley hain" },
    { number: 24, arabic: "وَلَقَدْ عَلِمْنَا ٱلْمُسْتَقْدِمِينَ مِنكُمْ وَلَقَدْ عَلِمْنَا ٱلْمُسْتَـْٔخِرِينَ", transliteration: "Walaqad AAalimna almustaqdimeena minkum walaqad AAalimna almustakhireena", transliterationB: "Wa la qad 'alimnal mustaqdimeena minkum wa laqad 'alimnal mustaakhireen", english: "To Us are known those of you who hasten forward, and those who lag behind", romanUrdu: "Pehle jo log tum mein se ho guzre hain unko bhi humne dekh rakkha hai, aur baad ke aaney waley bhi hamari nigaah mein hain" },
    { number: 25, arabic: "وَإِنَّ رَبَّكَ هُوَ يَحْشُرُهُمْ ۚ إِنَّهُۥ حَكِيمٌ عَلِيمٌۭ", transliteration: "Wainna rabbaka huwa yahshuruhum innahu hakeemun AAaleemun", transliterationB: "Wa inna Rabbaka Huwa yahshuruhum; innahoo Hakeem 'Aleem", english: "Assuredly it is thy Lord Who will gather them together: for He is perfect in Wisdom and Knowledge", romanUrdu: "Yaqeenan tumhara Rubb in sabko ikattha karega, woh hakeem(All-Wise) bhi hai aur aleem(All-Knowing) bhi" },
    { number: 26, arabic: "وَلَقَدْ خَلَقْنَا ٱلْإِنسَٰنَ مِن صَلْصَٰلٍۢ مِّنْ حَمَإٍۢ مَّسْنُونٍۢ", transliteration: "Walaqad khalaqna alinsana min salsalin min hamain masnoonin", transliterationB: "Wa laqad khalaqnal insaana min salsaalim min hama im masnoon", english: "We created man from sounding clay, from mud moulded into shape", romanUrdu: "Humne Insaan ko sadi (rotten) hui mitti ke sookhey gaarey (clay) se banaya" },
    { number: 27, arabic: "وَٱلْجَآنَّ خَلَقْنَٰهُ مِن قَبْلُ مِن نَّارِ ٱلسَّمُومِ", transliteration: "Waaljanna khalaqnahu min qablu min nari alssamoomi", transliterationB: "Waljaaanna khalaqnaahu min qablu min naaris samoom", english: "And the Jinn race, We had created before, from the fire of a scorching wind", romanUrdu: "Aur ussey pehle Jinno ko hum aag ki lapat se paida kar chuke thay" },
    { number: 28, arabic: "وَإِذْ قَالَ رَبُّكَ لِلْمَلَٰٓئِكَةِ إِنِّى خَٰلِقٌۢ بَشَرًۭا مِّن صَلْصَٰلٍۢ مِّنْ حَمَإٍۢ مَّسْنُونٍۢ", transliteration: "Waith qala rabbuka lilmalaikati innee khaliqun basharan min salsalin min hamain masnoonin", transliterationB: "Wa iz qaala Rabbuka lilmalaaa' ikati innee khaaliqum basharam min salsaalim min hama im masnoon", english: "Behold! thy Lord said to the angels: \"I am about to create man, from sounding clay from mud moulded into shape", romanUrdu: "Phir yaad karo us mauqe ko jab tumhare Rubb ne Farishton se kaha ke “ main sadi hui mitti ke sookhey gaarey se ek bashar paida kar raha hoon" },
    { number: 29, arabic: "فَإِذَا سَوَّيْتُهُۥ وَنَفَخْتُ فِيهِ مِن رُّوحِى فَقَعُوا۟ لَهُۥ سَٰجِدِينَ", transliteration: "Faitha sawwaytuhu wanafakhtu feehi min roohee faqaAAoo lahu sajideena", transliterationB: "Fa izaa sawwaituhoo wa nafakhtu feehi mir roohee faqa'oo lahoo saajideen", english: "When I have fashioned him (in due proportion) and breathed into him of My spirit, fall ye down in obeisance unto him", romanUrdu: "Jab main usey poora bana chukun aur us mein apni rooh se kuch phoonk doon to tum sab uske aagey sajde mein gir jana”" },
    { number: 30, arabic: "فَسَجَدَ ٱلْمَلَٰٓئِكَةُ كُلُّهُمْ أَجْمَعُونَ", transliteration: "Fasajada almalaikatu kulluhum ajmaAAoona", transliterationB: "Fasajadal malaaa'ikatu kulluhum ajma'oon", english: "So the angels prostrated themselves, all of them together", romanUrdu: "Chunanchey tamaam Farishton ne sajda kiya" },
    { number: 31, arabic: "إِلَّآ إِبْلِيسَ أَبَىٰٓ أَن يَكُونَ مَعَ ٱلسَّٰجِدِينَ", transliteration: "Illa ibleesa aba an yakoona maAAa alssajideena", transliterationB: "Illaaa ibleesa abaaa ai yakoona ma'as saajideen", english: "Not so Iblis: he refused to be among those who prostrated themselves", romanUrdu: "Siwaye Iblees ke, ke usne sajda karne walon ka saath dene se inkar kardiya" },
    { number: 32, arabic: "قَالَ يَٰٓإِبْلِيسُ مَا لَكَ أَلَّا تَكُونَ مَعَ ٱلسَّٰجِدِينَ", transliteration: "Qala ya ibleesu ma laka alla takoona maAAa alssajideena", transliterationB: "Qaala yaaa Ibleesu maa laka allaa takoona ma'as saajideen", english: "(Allah) said: \"O Iblis! what is your reason for not being among those who prostrated themselves", romanUrdu: "Rubb ne pucha “ aey Iblis , tujhey kya hua ke tu nay sajda karne walon ka saath na diya?”" },
    { number: 33, arabic: "قَالَ لَمْ أَكُن لِّأَسْجُدَ لِبَشَرٍ خَلَقْتَهُۥ مِن صَلْصَٰلٍۢ مِّنْ حَمَإٍۢ مَّسْنُونٍۢ", transliteration: "Qala lam akun liasjuda libasharin khalaqtahu min salsalin min hamain masnoonin", transliterationB: "Qaala lam akul li asjuda libasharin khalaqtahoo min salsaalim min hama im masnoon", english: "(Iblis) said: \"I am not one to prostrate myself to man, whom Thou didst create from sounding clay, from mud moulded into shape", romanUrdu: "Usne kaha “mera yeh kaam nahin hai ke main is bashar ko sajda karoon jisey tu nay sadi hui mitti ke sookhey gaarey se paida kiya hai”" },
    { number: 34, arabic: "قَالَ فَٱخْرُجْ مِنْهَا فَإِنَّكَ رَجِيمٌۭ", transliteration: "Qala faokhruj minha fainnaka rajeemun", transliterationB: "Qaala fakhruj minhaa fa innaka rajeem", english: "(Allah) said: \"Then get thee out from here; for thou art rejected, accursed", romanUrdu: "Rubb ne farmaya “accha to nikal jaa yahan se kyunke tu mardood(accursed) hai" },
    { number: 35, arabic: "وَإِنَّ عَلَيْكَ ٱللَّعْنَةَ إِلَىٰ يَوْمِ ٱلدِّينِ", transliteration: "Wainna AAalayka allaAAnata ila yawmi alddeeni", transliterationB: "Wa inna 'alikal la'nata ilaa Yawmid Deen", english: "And the curse shall be on thee till the day of Judgment", romanUrdu: "Aur ab roz-e-jaza tak tujhpar lanat hai”" },
    { number: 36, arabic: "قَالَ رَبِّ فَأَنظِرْنِىٓ إِلَىٰ يَوْمِ يُبْعَثُونَ", transliteration: "Qala rabbi faanthirnee ila yawmi yubAAathoona", transliterationB: "Qaala Rabbi fa anzirneee ilaa Yawmi yub'asoon", english: "(Iblis) said: \"O my Lord! give me then respite till the Day the (dead) are raised", romanUrdu: "Usne arz kiya “mere Rubb, yeh baat hai to phir mujhey us roz tak ke liye mohlat de jabke sab Insaan dobara uthaye jayenge”" },
    { number: 37, arabic: "قَالَ فَإِنَّكَ مِنَ ٱلْمُنظَرِينَ", transliteration: "Qala fainnaka mina almunthareena", transliterationB: "Qaala fa innaka minal munzareen", english: "(Allah) said: \"Respite is granted thee", romanUrdu: "Farmaya “ accha, tujhey mohlat hai" },
    { number: 38, arabic: "إِلَىٰ يَوْمِ ٱلْوَقْتِ ٱلْمَعْلُومِ", transliteration: "Ila yawmi alwaqti almaAAloomi", transliterationB: "Ilaa Yawmil waqtil ma'loom", english: "Till the Day of the Time appointed", romanUrdu: "Us din tak jiska waqt humein maloom hai”" },
    { number: 39, arabic: "قَالَ رَبِّ بِمَآ أَغْوَيْتَنِى لَأُزَيِّنَنَّ لَهُمْ فِى ٱلْأَرْضِ وَلَأُغْوِيَنَّهُمْ أَجْمَعِينَ", transliteration: "Qala rabbi bima aghwaytanee laozayyinanna lahum fee alardi walaoghwiyannahum ajmaAAeena", transliterationB: "Qaala Rabbi bimaaa aghwaitanee la uzayyinaana lahum fil ardi wa la ughwiyan nahum ajma'een", english: "(Iblis) said: \"O my Lord! because Thou hast put me in the wrong, I will make (wrong) fair-seeming to them on the earth, and I will put them all in the wrong", romanUrdu: "Woh bola “mere Rubb, jaisa tu nay mujhey behkaya usi tarah ab main zameen mein inke liye dil farebiyan paida karke in sabko behka dunga" },
    { number: 40, arabic: "إِلَّا عِبَادَكَ مِنْهُمُ ٱلْمُخْلَصِينَ", transliteration: "Illa AAibadaka minhumu almukhlaseena", transliterationB: "Illaa 'ibaadaka minhumul mukhlaseen", english: "Except Thy servants among them, sincere and purified (by Thy Grace)", romanUrdu: "Siwaye tere un bandon ke jinhein tu nay inmein se khaalis karliya ho”" },
    { number: 41, arabic: "قَالَ هَٰذَا صِرَٰطٌ عَلَىَّ مُسْتَقِيمٌ", transliteration: "Qala hatha siratun AAalayya mustaqeemun", transliterationB: "Qaala haaza Siraatun 'alaiya Mustaqeem", english: "(Allah) said: \"This (way of My sincere servants) is indeed a way that leads straight to Me", romanUrdu: "Farmaya “yeh raasta hai jo seedha mujh tak pahunchta hai" },
    { number: 42, arabic: "إِنَّ عِبَادِى لَيْسَ لَكَ عَلَيْهِمْ سُلْطَٰنٌ إِلَّا مَنِ ٱتَّبَعَكَ مِنَ ٱلْغَاوِينَ", transliteration: "Inna AAibadee laysa laka AAalayhim sultanun illa mani ittabaAAaka mina alghaweena", transliterationB: "Inna 'ibaadee laisa laka 'alaihim sultaanun illaa manittaba'aka minal ghaaween", english: "For over My servants no authority shalt thou have, except such as put themselves in the wrong and follow thee", romanUrdu: "Beshak , jo mere haqiqi banday hain unpar tera bas na chalega. Tera bas to sirf un behke huey logon hi par chalega jo teri pairwi karein" },
    { number: 43, arabic: "وَإِنَّ جَهَنَّمَ لَمَوْعِدُهُمْ أَجْمَعِينَ", transliteration: "Wainna jahannama lamawAAiduhum ajmaAAeena", transliterationB: "Wa inna jahannama lamaw'iduhum ajma'een", english: "And verily, Hell is the promised abode for them all", romanUrdu: "Aur un sab ke liye jahannum ki waeed(destined) hai”" },
    { number: 44, arabic: "لَهَا سَبْعَةُ أَبْوَٰبٍۢ لِّكُلِّ بَابٍۢ مِّنْهُمْ جُزْءٌۭ مَّقْسُومٌ", transliteration: "Laha sabAAatu abwabin likulli babin minhum juzon maqsoomun", transliterationB: "Lahaa sab'atu abwaab; likulli baabim minhum juz'um maqsoom", english: "To it are seven gates: for each of those gates is a (special) class (of sinners) assigned", romanUrdu: "Yeh jahannum ( jiski waeed pairwan e Iblis ke liye ki gayi hai) uske saat (seven) darwaze hain, har darwaze keliye unmein se ek hissa makhsoos kardiya gaya hai" },
    { number: 45, arabic: "إِنَّ ٱلْمُتَّقِينَ فِى جَنَّٰتٍۢ وَعُيُونٍ", transliteration: "Inna almuttaqeena fee jannatin waAAuyoonin", transliterationB: "Innal muttaqeena fee Jannaatinw wa 'uyoon", english: "The righteous (will be) amid gardens and fountains (of clear-flowing water)", romanUrdu: "Ba-khilaf iske muttaqi log baaghon (gardens) aur chashmon (fountains) mein hongey" },
    { number: 46, arabic: "ٱدْخُلُوهَا بِسَلَٰمٍ ءَامِنِينَ", transliteration: "Odkhulooha bisalamin amineena", transliterationB: "Udkhuloohaa bisalaamin aamineen", english: "(Their greeting will be): \"Enter ye here in peace and security", romanUrdu: "Aur unse kaha jayega ke dakhil ho jao inmein salamati ke saath bekhauf o khatar" },
    { number: 47, arabic: "وَنَزَعْنَا مَا فِى صُدُورِهِم مِّنْ غِلٍّ إِخْوَٰنًا عَلَىٰ سُرُرٍۢ مُّتَقَٰبِلِينَ", transliteration: "WanazaAAna ma fee sudoorihim min ghillin ikhwanan AAala sururin mutaqabileena", transliterationB: "Wa naza'naa ma fee sudoorihim min ghillin ikhwaanan 'alaa sururim mutaqaabileen", english: "And We shall remove from their hearts any lurking sense of injury: (they will be) brothers (joyfully) facing each other on thrones (of dignity)", romanUrdu: "Unke dilon mein jo thodi bahut khot-kapat hogi usey hum nikal denge, woh aapas mein bhai bhai bankar aamne saamne takhaton par baithenge" },
    { number: 48, arabic: "لَا يَمَسُّهُمْ فِيهَا نَصَبٌۭ وَمَا هُم مِّنْهَا بِمُخْرَجِينَ", transliteration: "La yamassuhum feeha nasabun wama hum minha bimukhrajeena", transliterationB: "Laa yamas suhum feehaa nasabunw wa maa hum minhaa bimukhrajeen", english: "There no sense of fatigue shall touch them, nor shall they (ever) be asked to leave", romanUrdu: "Unhein na wahan kisi mushaqqat se paala padega aur na woh wahan se nikale jayenge" },
    { number: 49, arabic: "۞ نَبِّئْ عِبَادِىٓ أَنِّىٓ أَنَا ٱلْغَفُورُ ٱلرَّحِيمُ", transliteration: "Nabbi AAibadee annee ana alghafooru alrraheemu", transliterationB: "Nabbi' 'ibaadeee annneee anal Ghafoorur Raheem", english: "Tell My servants that I am indeed the Oft-forgiving, Most Merciful", romanUrdu: "(Aey Nabi), mere bandon ko khabar de do ke main bahut darguzar karne wala (Forgiving) aur Raheem hoon" },
    { number: 50, arabic: "وَأَنَّ عَذَابِى هُوَ ٱلْعَذَابُ ٱلْأَلِيمُ", transliteration: "Wa anna AAathabee huwa alAAathabu alaleemu", transliterationB: "Wa anna 'azaabee uwal 'azaabul aleem", english: "And that My Penalty will be indeed the most grievous Penalty", romanUrdu: "Magar iske saath mera azaab bhi nihayat dardnaak azaab hai" },
    { number: 51, arabic: "وَنَبِّئْهُمْ عَن ضَيْفِ إِبْرَٰهِيمَ", transliteration: "Wanabbihum AAan dayfi ibraheema", transliterationB: "Wa nabbi'hum 'an daifi Ibraaheem", english: "Tell them about the guests of Abraham", romanUrdu: "Aur inhein zara Ibrahim ke mehmano ka qissa sunao" },
    { number: 52, arabic: "إِذْ دَخَلُوا۟ عَلَيْهِ فَقَالُوا۟ سَلَٰمًۭا قَالَ إِنَّا مِنكُمْ وَجِلُونَ", transliteration: "Ith dakhaloo AAalayhi faqaloo salaman qala inna minkum wajiloona", transliterationB: "Iz dakhaloo 'alaihi faqaaloo salaaman qaala innaa minkum wajiloon", english: "When they entered his presence and said, \"Peace!\" He said, \"We feel afraid of you", romanUrdu: "Jab woh aaye uske haan aur kaha “Salaam ho tumpar,” to usne kaha “humein tumse darr lagta hai”" },
    { number: 53, arabic: "قَالُوا۟ لَا تَوْجَلْ إِنَّا نُبَشِّرُكَ بِغُلَٰمٍ عَلِيمٍۢ", transliteration: "Qaloo la tawjal inna nubashshiruka bighulamin AAaleemin", transliterationB: "Qaaloo la tawjal innaa nubashshiruka bighulaamin 'aleem", english: "They said: \"Fear not! We give thee glad tidings of a son endowed with wisdom", romanUrdu: "Unhon ne jawab diya “ daro nahin, hum tumhein ek baday siyane ladke ki basharat dete hain”" },
    { number: 54, arabic: "قَالَ أَبَشَّرْتُمُونِى عَلَىٰٓ أَن مَّسَّنِىَ ٱلْكِبَرُ فَبِمَ تُبَشِّرُونَ", transliteration: "Qala abashshartumoonee AAala an massaniya alkibaru fabima tubashshirooni", transliterationB: "Qaala abashshartumoonee 'alaaa am massaniyal kibaru fabima tubashshiroon", english: "He said: \"Do ye give me glad tidings that old age has seized me? Of what, then, is your good news", romanUrdu: "Ibrahim ne kaha “ kya tum is budhape mein mujhey aulad ki basharat dete ho? Zara socho to sahih ke yeh kaisi basharat tum mujhey de rahey ho?”" },
    { number: 55, arabic: "قَالُوا۟ بَشَّرْنَٰكَ بِٱلْحَقِّ فَلَا تَكُن مِّنَ ٱلْقَٰنِطِينَ", transliteration: "Qaloo bashsharnaka bialhaqqi fala takun mina alqaniteena", transliterationB: "Qaaloo bashsharnaaka bilhaqqi falaa takum minal qaaniteen", english: "They said: \"We give thee glad tidings in truth: be not then in despair", romanUrdu: "Unhon ne jawab diya “ hum tumhein bar haqq basharat de rahey hain, tum mayous na ho”" },
    { number: 56, arabic: "قَالَ وَمَن يَقْنَطُ مِن رَّحْمَةِ رَبِّهِۦٓ إِلَّا ٱلضَّآلُّونَ", transliteration: "Qala waman yaqnatu min rahmati rabbihi illa alddalloona", transliterationB: "Qaala wa mai yaqnatu mir rahmati Rabbiheee illad daaaloon", english: "He said: \"And who despairs of the mercy of his Lord, but such as go astray", romanUrdu: "Ibrahim ne kaha “ apne Rubb ki rehmat se mayous to gumraah log hi hua karte hain”" },
    { number: 57, arabic: "قَالَ فَمَا خَطْبُكُمْ أَيُّهَا ٱلْمُرْسَلُونَ", transliteration: "Qala fama khatbukum ayyuha almursaloona", transliterationB: "Qaala famaa khatbukum aiyuhal mursaloon", english: "Abraham said: \"What then is the business on which ye (have come), O ye messengers (of Allah)", romanUrdu: "Phir Ibrahim ne pucha “aey faristaad-gaan-e-Ilahi(messengers of Allah), woh mohim (expedition) kya hai jispar aap hazraat tashreef laye hain?”" },
    { number: 58, arabic: "قَالُوٓا۟ إِنَّآ أُرْسِلْنَآ إِلَىٰ قَوْمٍۢ مُّجْرِمِينَ", transliteration: "Qaloo inna orsilna ila qawmin mujrimeena", transliterationB: "Qaaloo innaaa ursilnaaa ilaa qawmim mujrimeen", english: "They said: \"We have been sent to a people (deep) in sin", romanUrdu: "Woh bole, “hum ek mujreem qaum ki taraf bhejhe gaye hain" },
    { number: 59, arabic: "إِلَّآ ءَالَ لُوطٍ إِنَّا لَمُنَجُّوهُمْ أَجْمَعِينَ", transliteration: "Illa ala lootin inna lamunajjoohum ajmaAAeena", transliterationB: "Illaaa Aala Loot; innaa lamunajjoohum ajma'een", english: "Excepting the adherents of Lut: them we are certainly (charged) to save (from harm),- All", romanUrdu: "Sirf Lut ke ghar waley mustasna (exception) hain, un sab ko hum bacha lenge" },
    { number: 60, arabic: "إِلَّا ٱمْرَأَتَهُۥ قَدَّرْنَآ ۙ إِنَّهَا لَمِنَ ٱلْغَٰبِرِينَ", transliteration: "Illa imraatahu qaddarna innaha lamina alghabireena", transliterationB: "Illam ra atahoo qaddarnaaa innahaa laminal ghaabireen", english: "Except his wife, who, We have ascertained, will be among those who will lag behind", romanUrdu: "Siwaye uski biwi ke jiske liye (Allah farmata hai ke) humne muqaddar kardiya hai ke woh peechey reh janey walon mein shamil rahegi”" },
    { number: 61, arabic: "فَلَمَّا جَآءَ ءَالَ لُوطٍ ٱلْمُرْسَلُونَ", transliteration: "Falamma jaa ala lootin almursaloona", transliterationB: "Falamma jaaa'a Aala Lootinil mursaloon", english: "At length when the messengers arrived among the adherents of Lut", romanUrdu: "Phir jab yeh Faristaade Lut ke haan pahunchey" },
    { number: 62, arabic: "قَالَ إِنَّكُمْ قَوْمٌۭ مُّنكَرُونَ", transliteration: "Qala innakum qawmun munkaroona", transliterationB: "Qaala innakum qawmum munkaroon", english: "He said: \"Ye appear to be uncommon folk", romanUrdu: "To usne kaha “aap log ajnabi maloom hotey hain”" },
    { number: 63, arabic: "قَالُوا۟ بَلْ جِئْنَٰكَ بِمَا كَانُوا۟ فِيهِ يَمْتَرُونَ", transliteration: "Qaloo bal jinaka bima kanoo feehi yamtaroona", transliterationB: "Qaaloo bal ji'naaka bimaa kaanoo feehi yamtaroon", english: "They said: \"Yea, we have come to thee to accomplish that of which they doubt", romanUrdu: "Unhon ne jawab diya “nahin, balke hum wahi cheez lekar aaye hain jiske aane mein yeh log shakk kar rahey thay" },
    { number: 64, arabic: "وَأَتَيْنَٰكَ بِٱلْحَقِّ وَإِنَّا لَصَٰدِقُونَ", transliteration: "Waataynaka bialhaqqi wainna lasadiqoona", transliterationB: "Wa atainaaka bilhaqqi wa innaa lasaadiqoon", english: "We have brought to thee that which is inevitably due, and assuredly we tell the truth", romanUrdu: "Hum tumse sach kehte hain ke hum haqq ke saath tumhare paas aaye hain" },
    { number: 65, arabic: "فَأَسْرِ بِأَهْلِكَ بِقِطْعٍۢ مِّنَ ٱلَّيْلِ وَٱتَّبِعْ أَدْبَٰرَهُمْ وَلَا يَلْتَفِتْ مِنكُمْ أَحَدٌۭ وَٱمْضُوا۟ حَيْثُ تُؤْمَرُونَ", transliteration: "Faasri biahlika biqitAAin mina allayli waittabiAA adbarahum wala yaltafit minkum ahadun waimdoo haythu tumaroona", transliterationB: "Fa asri bi ahlika biqit'im minal laili wattabi' adbaarahum wa laa yaltafit minkum ahadunw wamdoo haisu tu'maroon", english: "Then travel by night with thy household, when a portion of the night (yet remains), and do thou bring up the rear: let no one amongst you look back, but pass on whither ye are ordered", romanUrdu: "Lihaza ab tum kuch raat rahey apne ghar walon ko lekar nikal jao aur khud unke peechey peechey chalo, tum mein se koi palat kar na dekhe bas seedhey chale jao jidhar jaane ka tumhein hukum diya jaa raha hai”" },
    { number: 66, arabic: "وَقَضَيْنَآ إِلَيْهِ ذَٰلِكَ ٱلْأَمْرَ أَنَّ دَابِرَ هَٰٓؤُلَآءِ مَقْطُوعٌۭ مُّصْبِحِينَ", transliteration: "Waqadayna ilayhi thalika alamra anna dabira haolai maqtooAAun musbiheena", transliterationB: "Wa qadainaaa ilaihi zaalikal amra anna daabira haaa'ulaaa'i maqtoo'um musbiheen", english: "And We made known this decree to him, that the last remnants of those (sinners) should be cut off by the morning", romanUrdu: "Aur usey humne apna yeh faisla pahuncha diya ke subah hotey hotey in logon ki jadd (roots) kaat di jayegi" },
    { number: 67, arabic: "وَجَآءَ أَهْلُ ٱلْمَدِينَةِ يَسْتَبْشِرُونَ", transliteration: "Wajaa ahlu almadeenati yastabshiroona", transliterationB: "Wa jaaa'a ahlul madeenati yastabshiroon", english: "The inhabitants of the city came in (mad) joy (at news of the young men)", romanUrdu: "Itne mein shehar ke log khushi ke maarey betab hokar Lut ke ghar chadh aaye" },
    { number: 68, arabic: "قَالَ إِنَّ هَٰٓؤُلَآءِ ضَيْفِى فَلَا تَفْضَحُونِ", transliteration: "Qala inna haolai dayfee fala tafdahooni", transliterationB: "Qaala inna haaa'ulaaa'i daifee falaa tafdahoon", english: "Lut said: \"These are my guests: disgrace me not", romanUrdu: "Lut ne kaha “bhaiyon, yeh mere mehmaan hain, meri fazihat (dishonour) na karo" },
    { number: 69, arabic: "وَٱتَّقُوا۟ ٱللَّهَ وَلَا تُخْزُونِ", transliteration: "Waittaqoo Allaha wala tukhzooni", transliterationB: "Wattaqul laaha wa laa tukhzoon", english: "But fear Allah, and shame me not", romanUrdu: "Allah se daro, mujhey ruswa na karo”" },
    { number: 70, arabic: "قَالُوٓا۟ أَوَلَمْ نَنْهَكَ عَنِ ٱلْعَٰلَمِينَ", transliteration: "Qaloo awalam nanhaka AAani alAAalameena", transliterationB: "Qaalooo awalam nanhaka 'anil 'aalameen", english: "They said: \"Did we not forbid thee (to speak) for all and sundry", romanUrdu: "Woh boley “kya hum baaraha tumhein mana nahin kar chuke hain ke duniya bhar ke thekedar na bano?”" },
    { number: 71, arabic: "قَالَ هَٰٓؤُلَآءِ بَنَاتِىٓ إِن كُنتُمْ فَٰعِلِينَ", transliteration: "Qala haolai banatee in kuntum faAAileena", transliterationB: "Qaala haaa'ulaaa'i banaateee in kuntum faa'ileen", english: "He said: \"There are my daughters (to marry), if ye must act (so)", romanUrdu: "Lut ne aajiz hokar kaha “agar tumhein kuch karna hi hai to yeh meri betiyan maujood hain”" },
    { number: 72, arabic: "لَعَمْرُكَ إِنَّهُمْ لَفِى سَكْرَتِهِمْ يَعْمَهُونَ", transliteration: "LaAAamruka innahum lafee sakratihim yaAAmahoona", transliterationB: "La'amruka innahum lafee sakratihim ya'mahoon", english: "Verily, by thy life (O Prophet), in their wild intoxication, they wander in distraction, to and fro", romanUrdu: "Teri jaan ki kasam aey Nabi, us waqt unpar ek nasha sa chadha hua tha jismein woh aape se bahar huye jatey thay" },
    { number: 73, arabic: "فَأَخَذَتْهُمُ ٱلصَّيْحَةُ مُشْرِقِينَ", transliteration: "Faakhathathumu alssayhatu mushriqeena", transliterationB: "Fa akhazat humus saihatu mushriqeen", english: "But the (mighty) Blast overtook them before morning", romanUrdu: "Aakhir e kaar pow phathte hi unko ek zabardast dhamake ne aa liya (severe blast overtook them at dawn)" },
    { number: 74, arabic: "فَجَعَلْنَا عَٰلِيَهَا سَافِلَهَا وَأَمْطَرْنَا عَلَيْهِمْ حِجَارَةًۭ مِّن سِجِّيلٍ", transliteration: "FajaAAalna AAaliyaha safilaha waamtarna AAalayhim hijaratan min sijjeelin", transliterationB: "Faja'alnaa 'aaliyahaa saafilahaa wa amtamaa 'alaihim hijaaratam min sjijjeel", english: "And We turned (the cities) upside down, and rained down on them brimstones hard as baked clay", romanUrdu: "Aur humne us basti ko talpat karke rakh diya aur unpar paki (baked) hui mitti ke pattharon ki baarish barsa di" },
    { number: 75, arabic: "إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّلْمُتَوَسِّمِينَ", transliteration: "Inna fee thalika laayatin lilmutawassimeena", transliterationB: "Inna fee zaalika la Aayaatil lilmutawassimeen", english: "Behold! in this are Signs for those who by tokens do understand", romanUrdu: "Is waqiye mein badi nishaniyan hain un logon ke liye jo saahib-e-firasat hain" },
    { number: 76, arabic: "وَإِنَّهَا لَبِسَبِيلٍۢ مُّقِيمٍ", transliteration: "Wainnaha labisabeelin muqeemin", transliterationB: "Wa innahaa labi sabeelim muqeem", english: "And the (cities were) right on the high-road", romanUrdu: "Aur woh ilaqa (jahan yeh waqiya pesh aaya tha) guzar gaah e aam (high way) par waqeh hai" },
    { number: 77, arabic: "إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّلْمُؤْمِنِينَ", transliteration: "Inna fee thalika laayatan lilmumineena", transliterationB: "Inna fee zaalika la Aayatal lilmu'mineen", english: "Behold! in this is a sign for those who believed", romanUrdu: "Usmein samaan e ibrat hai un logon ke liye jo sahib e iman hain" },
    { number: 78, arabic: "وَإِن كَانَ أَصْحَٰبُ ٱلْأَيْكَةِ لَظَٰلِمِينَ", transliteration: "Wain kana ashabu alaykati lathalimeena", transliterationB: "Wa in kaana Ashaabul Aikati lazaalimeen", english: "And the Companions of the Wood were also wrong-doers", romanUrdu: "Aur Aikah waley zalim thay" },
    { number: 79, arabic: "فَٱنتَقَمْنَا مِنْهُمْ وَإِنَّهُمَا لَبِإِمَامٍۢ مُّبِينٍۢ", transliteration: "Faintaqamna minhum wainnahuma labiimamin mubeenin", transliterationB: "Fantaqamnaa minhum wa innahumaa labi imaamim mubeen", english: "So We exacted retribution from them. They were both on an open highway, plain to see", romanUrdu: "To dekhlo ke humne unsey bhi inteqam liya, aur in dono qaumon ke ujade huey ilaqe khuley raaste par waqeh hain" },
    { number: 80, arabic: "وَلَقَدْ كَذَّبَ أَصْحَٰبُ ٱلْحِجْرِ ٱلْمُرْسَلِينَ", transliteration: "Walaqad kaththaba ashabu alhijri almursaleena", transliterationB: "Wa laqad kazzaba ashaabul Hijril mursaleen", english: "The Companions of the Rocky Tract also rejected the messengers", romanUrdu: "Hijr ke log bhi Rasoolon ki takzeeb kar chuke hain" },
    { number: 81, arabic: "وَءَاتَيْنَٰهُمْ ءَايَٰتِنَا فَكَانُوا۟ عَنْهَا مُعْرِضِينَ", transliteration: "Waataynahum ayatina fakanoo AAanha muAArideena", transliterationB: "Wa aatainaahum Aayaatinaa fakaanoo 'anhaa mu'rideen", english: "We sent them Our Signs, but they persisted in turning away from them", romanUrdu: "Humne apni aayat unke paas bheji, apni nishaniyan unko dikhayi, magar woh sabko nazar-andaz (ignore) hi karte rahey" },
    { number: 82, arabic: "وَكَانُوا۟ يَنْحِتُونَ مِنَ ٱلْجِبَالِ بُيُوتًا ءَامِنِينَ", transliteration: "Wakanoo yanhitoona mina aljibali buyootan amineena", transliterationB: "Wa kaanoo yanhitoona minal jibaali buyootan aamineen", english: "Out of the mountains did they hew (their) edifices, (feeling themselves) secure", romanUrdu: "Woh pahad tarash tarash kar makaan banate thay aur apni jagah bilkul be-khauf aur mutmaeen thay" },
    { number: 83, arabic: "فَأَخَذَتْهُمُ ٱلصَّيْحَةُ مُصْبِحِينَ", transliteration: "Faakhathathumu alssayhatu musbiheena", transliterationB: "Fa akhazat humus saihatu musbiheen", english: "But the (mighty) Blast seized them of a morning", romanUrdu: "Aakhir e kaar ek zabardast dhamake ne unko subah hotey hi aa liya" },
    { number: 84, arabic: "فَمَآ أَغْنَىٰ عَنْهُم مَّا كَانُوا۟ يَكْسِبُونَ", transliteration: "Fama aghna AAanhum ma kanoo yaksiboona", transliterationB: "Famaaa aghnaa 'anhum maa kaanoo yaksiboon", english: "And of no avail to them was all that they did (with such art and care)", romanUrdu: "Aur unki kamayi unke kuch kaam na aayi" },
    { number: 85, arabic: "وَمَا خَلَقْنَا ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَآ إِلَّا بِٱلْحَقِّ ۗ وَإِنَّ ٱلسَّاعَةَ لَءَاتِيَةٌۭ ۖ فَٱصْفَحِ ٱلصَّفْحَ ٱلْجَمِيلَ", transliteration: "Wama khalaqna alssamawati waalarda wama baynahuma illa bialhaqqi wainna alssaAAata laatiyatun faisfahi alssafha aljameela", transliterationB: "Wa maa khalaqnas samaawaati wal arda wa maa bainahumaaa illaa bilhaqq; wa innas Saa'ata la aatiyatun fasfahis safhal jameel", english: "We created not the heavens, the earth, and all between them, but for just ends. And the Hour is surely coming (when this will be manifest). So overlook (any human faults) with gracious forgiveness", romanUrdu: "Humne zameen aur aasman ko aur unki sab maujoodaat ko haqq ke siwa kisi aur buniyaad par khalq (create) nahin kiya hai, aur faisle ki ghadi yaqeenan aane wali hai. Pas (aey Muhammad), tum (in logon ki behudgiyon par) shareefana darguzar se kaam lo" },
    { number: 86, arabic: "إِنَّ رَبَّكَ هُوَ ٱلْخَلَّٰقُ ٱلْعَلِيمُ", transliteration: "Inna rabbaka huwa alkhallaqu alAAaleemu", transliterationB: "Inna Rabbaka Huwal khallaaqul 'aleem", english: "For verily it is thy Lord who is the Master-Creator, knowing all things", romanUrdu: "Yaqeenan tumahra Rubb sab ka khaliq hai aur sab kuch jaanta hai" },
    { number: 87, arabic: "وَلَقَدْ ءَاتَيْنَٰكَ سَبْعًۭا مِّنَ ٱلْمَثَانِى وَٱلْقُرْءَانَ ٱلْعَظِيمَ", transliteration: "Walaqad ataynaka sabAAan mina almathanee waalqurana alAAatheema", transliterationB: "Wa laqad aatainaaka sab'am mnal masaanee wal Qur-aanal 'azeem", english: "And We have bestowed upon thee the Seven Oft-repeated (verses) and the Grand Qur'an", romanUrdu: "Humne tumko saat (seven) aisi aayatein de rakkhi hain jo baar baar dohrayi janey ke layiq hain, aur tumhein Quran e azeem ata kiya hai" },
    { number: 88, arabic: "لَا تَمُدَّنَّ عَيْنَيْكَ إِلَىٰ مَا مَتَّعْنَا بِهِۦٓ أَزْوَٰجًۭا مِّنْهُمْ وَلَا تَحْزَنْ عَلَيْهِمْ وَٱخْفِضْ جَنَاحَكَ لِلْمُؤْمِنِينَ", transliteration: "La tamuddanna AAaynayka ila ma mattaAAna bihi azwajan minhum wala tahzan AAalayhim waikhfid janahaka lilmumineena", transliterationB: "Laa tamuddanna 'ainaika ilaa maa matta 'naa biheee azwaajam minhum wa laa tahzan 'alaihim wakhfid janaahaka lilmu 'mineen", english: "Strain not thine eyes. (Wistfully) at what We have bestowed on certain classes of them, nor grieve over them: but lower thy wing (in gentleness) to the believers", romanUrdu: "Tum us mata-e-duniya ki taraf aankh utha kar na dekho jo humne in mein se mukhtalif qisam ke logon ko de rakkhi hai, aur na inke haal par apna dil kudhao(grieve), inhein chodh kar iman laney walon ki taraf jhuko" },
    { number: 89, arabic: "وَقُلْ إِنِّىٓ أَنَا ٱلنَّذِيرُ ٱلْمُبِينُ", transliteration: "Waqul innee ana alnnatheeru almubeenu", transliterationB: "Wa qul inneee anan nazeerul mubeen", english: "And say: \"I am indeed he that warneth openly and without ambiguity", romanUrdu: "Aur (na maanne walon se) kehdo ke main to saaf saaf tambeeh(warn) karne wala hoon" },
    { number: 90, arabic: "كَمَآ أَنزَلْنَا عَلَى ٱلْمُقْتَسِمِينَ", transliteration: "Kama anzalna AAala almuqtasimeena", transliterationB: "Kamaaa anzalnaa 'alal muqtasimeen", english: "(Of just such wrath) as We sent down on those who divided (Scripture into arbitrary parts)", romanUrdu: "Yeh usi ki tarah ki tambeeh hai jaisi humne un tafarraqe pardazon(those who make division) ki taraf bheji thi" },
    { number: 91, arabic: "ٱلَّذِينَ جَعَلُوا۟ ٱلْقُرْءَانَ عِضِينَ", transliteration: "Allatheena jaAAaloo alqurana AAideena", transliterationB: "Allazeena ja'alul Quraana'ideen", english: "(So also on such) as have made Qur'an into shreds (as they please)", romanUrdu: "Jinhon ne apne Quran ko tukde tukde kar dala hai" },
    { number: 92, arabic: "فَوَرَبِّكَ لَنَسْـَٔلَنَّهُمْ أَجْمَعِينَ", transliteration: "Fawarabbika lanasalannahum ajmaAAeena", transliterationB: "Fawa Rabbika lanas'a lannahum ajma'een", english: "Therefore, by the Lord, We will, of a surety, call them to account", romanUrdu: "To kasam hai tere Rubb ki, hum zaroor in sabse puchenge" },
    { number: 93, arabic: "عَمَّا كَانُوا۟ يَعْمَلُونَ", transliteration: "AAamma kanoo yaAAmaloona", transliterationB: "Ammaa kaanoo ya'maloon", english: "For all their deeds", romanUrdu: "Ke tum kya karte rahey ho" },
    { number: 94, arabic: "فَٱصْدَعْ بِمَا تُؤْمَرُ وَأَعْرِضْ عَنِ ٱلْمُشْرِكِينَ", transliteration: "FaisdaAA bima tumaru waaAArid AAani almushrikeena", transliterationB: "Fasda' bimaa tu'maru wa a'rid anil mushrikeen", english: "Therefore expound openly what thou art commanded, and turn away from those who join false gods with Allah", romanUrdu: "Pas (aey Nabi) jis cheez ka tumhein hukum diya jaa raha hai usey hankey pukare kehdo(proclaim publicly) aur shirk karne walon ki zara parwah na karo" },
    { number: 95, arabic: "إِنَّا كَفَيْنَٰكَ ٱلْمُسْتَهْزِءِينَ", transliteration: "Inna kafaynaka almustahzieena", transliterationB: "Innaa kafainaakal mustahzi'een", english: "For sufficient are We unto thee against those who scoff", romanUrdu: "Tumhari taraf se hum un mazaaq udane walon ki khabar lenay ke liye kafi hain" },
    { number: 96, arabic: "ٱلَّذِينَ يَجْعَلُونَ مَعَ ٱللَّهِ إِلَٰهًا ءَاخَرَ ۚ فَسَوْفَ يَعْلَمُونَ", transliteration: "Allatheena yajAAaloona maAAa Allahi ilahan akhara fasawfa yaAAlamoona", transliterationB: "Allazeena yaj'aloona ma'al laahi ilaahan aakhar; fasawfa ya'lamoon", english: "Those who adopt, with Allah, another god: but soon will they come to know", romanUrdu: "Jo Allah ke saath kisi aur ko bhi khuda qarar dete hain anqareeb unhein maloom ho jayega" },
    { number: 97, arabic: "وَلَقَدْ نَعْلَمُ أَنَّكَ يَضِيقُ صَدْرُكَ بِمَا يَقُولُونَ", transliteration: "Walaqad naAAlamu annaka yadeequ sadruka bima yaqooloona", transliterationB: "Wa laqad na'lamu annak yadeequ sadruka bimaa yaqooloon", english: "We do indeed know how thy heart is distressed at what they say", romanUrdu: "Humein maloom hai ke jo baatein yeh log tumpar banate hain unsey tumhare dil ko sakht koft hoti hai (heart is distressed)" },
    { number: 98, arabic: "فَسَبِّحْ بِحَمْدِ رَبِّكَ وَكُن مِّنَ ٱلسَّٰجِدِينَ", transliteration: "Fasabbih bihamdi rabbika wakun mina alssajideena", transliterationB: "Fasbbih bihamdi Rabbika wa kum minas saajideen", english: "But celebrate the praises of thy Lord, and be of those who prostrate themselves in adoration", romanUrdu: "Iska ilaaj yeh hai ke apne Rubb ki hamd ke saath uski tasbeeh karo, uski janaab mein sajda baja lao" },
    { number: 99, arabic: "وَٱعْبُدْ رَبَّكَ حَتَّىٰ يَأْتِيَكَ ٱلْيَقِينُ", transliteration: "WaoAAbud rabbaka hatta yatiyaka alyaqeenu", transliterationB: "Wa'bud Rabbaka hattaa yaatiyakal yaqeen", english: "And serve thy Lord until there come unto thee the Hour that is Certain", romanUrdu: "Aur us aakhri ghadi tak apne Rubb ki bandagi karte raho jiska aana yaqeeni hai" }
  ]
};
